157→/// Get a file's modification time as seconds since the Unix epoch.
158→fn mtime_secs(path: &Path) -> Result<i64, CacheError> {
159→    let metadata = fs::metadata(path)?;
160→    let mtime = metadata.modified()?;
161→    let duration = mtime
162→        .duration_since(SystemTime::UNIX_EPOCH)
163→        .unwrap_or_default();
164→    Ok(duration.as_secs() as i64)
